def _env_tile_cache_size(default: int = 128) -> int:
    raw = os.environ.get("ZE_TILE_CACHE_SIZE")
    if raw is None:
        return default
    try:
        return max(0, int(raw))
    except ValueError:
        return default


_TILE_CACHE_DEFAULT_CAPACITY = _env_tile_cache_size()


